import collections
import heapq

class Solution:
    def rearrangeCharacters(self, s: str) -> str:
        freq_map = collections.Counter(s)

        pq = []
        for char, freq in freq_map.items():
            heapq.heappush(pq, (-freq, char))

        result = []
        prev_char = None
        prev_freq = 0

        while pq:
            curr_freq, curr_char = heapq.heappop(pq)

            result.append(curr_char)

            if prev_char is not None and prev_freq < 0:
                heapq.heappush(pq, (prev_freq, prev_char))

            curr_freq += 1

            prev_char = curr_char
            prev_freq = curr_freq

        if prev_freq < 0:
            return ""
        else:
            return "".join(result)
